mapper.select:
SELECT pr.REVIEW_ID as reviewId, pr.PLACE_ID as placeId, pr.MEMBER_ID as memberId, pr.RATING as rating, pr.CONTENT as content, TO_CHAR(pr.CREATED_AT, 'YYYY-MM-DD HH24:MI') as createdAt, m2.NICKNAME as memberName, r.ROOM_NAME as roomName FROM PLACE_REVIEW pr LEFT JOIN MEMBER2 m2 ON pr.MEMBER_ID = m2.MEMBER_ID LEFT JOIN RESERVATION res ON pr.RESERVATION_ID = res.RESERVATION_ID LEFT JOIN ROOM r ON res.ROOM_ID = r.ROOM_ID
pr.PLACE_ID = #{placeId}
AND pr.CREATED_AT >= TO_DATE(#{startDate} || ' 00:00:00', 'YYYY-MM-DD HH24:MI:SS')
AND pr.CREATED_AT <= TO_DATE(#{endDate} || ' 23:59:59', 'YYYY-MM-DD HH24:MI:SS')
AND r.ROOM_ID = #{roomId}
AND pr.RATING = #{rating}
AND (m2.NICKNAME LIKE '%' || #{keyword} || '%' OR pr.CONTENT LIKE '%' || #{keyword} || '%')
ORDER BY pr.CREATED_AT DESC OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

SELECT COUNT(pr.REVIEW_ID) FROM PLACE_REVIEW pr LEFT JOIN MEMBER2 m2 ON pr.MEMBER_ID = m2.MEMBER_ID LEFT JOIN RESERVATION res ON pr.RESERVATION_ID = res.RESERVATION_ID LEFT JOIN ROOM r ON res.ROOM_ID = r.ROOM_ID
pr.PLACE_ID = #{placeId}
AND pr.CREATED_AT >= TO_DATE(#{startDate} || ' 00:00:00', 'YYYY-MM-DD HH24:MI:SS')
AND pr.CREATED_AT <= TO_DATE(#{endDate} || ' 23:59:59', 'YYYY-MM-DD HH24:MI:SS')
AND r.ROOM_ID = #{roomId}
AND pr.RATING = #{rating}
AND (m2.NICKNAME LIKE '%' || #{keyword} || '%' OR pr.CONTENT LIKE '%' || #{keyword} || '%')
